, "lesson_sequence_code": "RPL(A)28", "lesson_column_title": "Consolidation", "required_standard": 1}, {"matrix_code": "A6.6.013", "lesson_sequence_code": "RPL(A)30", "lesson_column_title": "Pre-Licence", "required_standard": 1}, {"matrix_code": "A6.6.015", "lesson_sequence_code": "RPL(A)26", "lesson_column_title": "Basic Instrument Flight", "required_standard": 3}, {"matrix_code": "A6.6.015", "lesson_sequence_code": "RPL(A)27", "lesson_column_title": "Consolidation", "required_standard": 3}, {"matrix_code": "A6.6.015", "lesson_sequence_code": "RPL(A)28", "lesson_column_title": "Consolidation", "required_standard": 1}, {"matrix_code": "A6.6.015", "lesson_sequence_code": "RPL(A)30", "lesson_column_title": "Pre-Licence", "required_standard": 1}, {"matrix_code": "A6.6.016", "lesson_sequence_code": "RPL(A)26", "lesson_column_title": "Basic Instrument Flight", "required_standard": 3}, {"matrix_code": "A6.6.016", "lesson_sequence_code": "RPL(A)27", "lesson_column_title": "Consolidation", "required_standard": 3}, {"matrix_code": "A6.6.016", "lesson_sequence_code": "RPL(A)28", "lesson_column_title": "Consolidation", "required_standard": 1}, {"matrix_code": "A6.6.016", "lesson_sequence_code": "RPL(A)30", "lesson_column_title": "Pre-Licence", "required_standard": 1}, {"matrix_code": "A6.6.017", "lesson_sequence_code": "RPL(A)26", "lesson_column_title": "Basic Instrument Flight", "required_standard": 3}, {"matrix_code": "A6.6.017", "lesson_sequence_code": "RPL(A)27", "lesson_column_title": "Consolidation", "required_standard": 3}, {"matrix_code": "A6.6.017", "lesson_sequence_code": "RPL(A)28", "lesson_column_title": "Consolidation", "required_standard": 1}, {"matrix_code": "A6.6.017", "lesson_sequence_code": "RPL(A)30", "lesson_column_title": "Pre-Licence", "required_standard": 1}, {"matrix_code": "A6.6.018", "lesson_sequence_code": "RPL(A)26", "lesson_column_title": "Basic Instrument Flight", "required_standard": 3}, {"matrix_code": "A6.6.018", "lesson_sequence_code": "RPL(A)27", "lesson_column_title": "Consolidation", "required_standard": 3}, {"matrix_code": "A6.6.018", "lesson_sequence_code": "RPL(A)28", "lesson_column_title": "Consolidation", "required_standard": 1}, {"matrix_code": "A6.6.018", "lesson_sequence_code": "RPL(A)30", "lesson_column_title": "Pre-Licence", "required_standard": 1}, {"matrix_code": "A6.6.019", "lesson_sequence_code": "RPL(A)26", "lesson_column_title": "Basic Instrument Flight", "required_standard": 3}, {"matrix_code": "A6.6.019", "lesson_sequence_code": "RPL(A)27", "lesson_column_title": "Consolidation", "required_standard": 3}, {"matrix_code": "A6.6.019", "lesson_sequence_code": "RPL(A)28", "lesson_column_title": "Consolidation", "required_standard": 1}, {"matrix_code": "A6.6.019", "lesson_sequence_code": "RPL(A)30", "lesson_column_title": "Pre-Licence", "required_standard": 1}]'::jsonb;
BEGIN
  SELECT id INTO target_course_id
  FROM public.training_courses
  WHERE title = 'CASA RPL(A) v1.2'
  ORDER BY last_updated DESC
  LIMIT 1;

  IF target_course_id IS NULL THEN
    RAISE NOTICE 'CASA RPL(A) v1.2 course not found; matrix import skipped.';
    RETURN;
  END IF;

  -- Requirements are derived from the planning matrix and can be rebuilt safely.
  -- Student assessment history references matrix rows, so rows are upserted and never bulk-deleted here.
  DELETE FROM public.syllabus_matrix_requirements WHERE course_id = target_course_id;

  FOR row_item IN SELECT * FROM jsonb_array_elements(row_data)
  LOOP
    INSERT INTO public.syllabus_matrix_rows (
      course_id,
      code,
      row_type,
      unit_code,
      element_code,
      parent_code,
      description,
      source_row_number,
      sort_order
    ) VALUES (
      target_course_id,
      row_item->>'code',
      row_item->>'row_type',
      row_item->>'unit_code',
      row_item->>'element_code',
      row_item->>'parent_code',
      row_item->>'description',
      (row_item->>'source_row_number')::integer,
      (row_item->>'sort_order')::integer
    )
    ON CONFLICT (course_id, code) DO UPDATE SET
      row_type = EXCLUDED.row_type,
      unit_code = EXCLUDED.unit_code,
      element_code = EXCLUDED.element_code,
      parent_code = EXCLUDED.parent_code,
      description = EXCLUDED.description,
      source_row_number = EXCLUDED.source_row_number,
      sort_order = EXCLUDED.sort_order;
  END LOOP;

  FOR req_item IN SELECT * FROM jsonb_array_elements(requirement_data)
  LOOP
    SELECT id INTO inserted_row_id
    FROM public.syllabus_matrix_rows
    WHERE course_id = target_course_id
      AND code = req_item->>'matrix_code';

    SELECT id INTO lesson_uuid
    FROM public.training_lessons
    WHERE course_id = target_course_id
      AND sequence_code = req_item->>'lesson_sequence_code'
    ORDER BY sort_order
    LIMIT 1;

    IF inserted_row_id IS NOT NULL THEN
      INSERT INTO public.syllabus_matrix_requirements (
        course_id,
        lesson_id,
        matrix_row_id,
        lesson_sequence_code,
        lesson_column_title,
        required_standard
      ) VALUES (
        target_course_id,
        lesson_uuid,
        inserted_row_id,
        req_item->>'lesson_sequence_code',
        req_item->>'lesson_column_title',
        (req_item->>'required_standard')::integer
      )
      ON CONFLICT (course_id, lesson_sequence_code, matrix_row_id) DO UPDATE SET
        lesson_id = EXCLUDED.lesson_id,
        lesson_column_title = EXCLUDED.lesson_column_title,
        required_standard = EXCLUDED.required_standard;
    END IF;
  END LOOP;
END $$;
